const err = $input.first().json;

const workflowName = err.workflow?.name || 'Unknown Workflow';
const nodeName     = err.execution?.lastNodeExecuted || 'Unknown Node';
const errorMsg     = err.execution?.error?.message || 'No message';
const errorStack   = err.execution?.error?.stack   || '';
const execId       = err.execution?.id  || 'N/A';
const execUrl      = err.execution?.url || '';
const timestamp    = new Date().toISOString();

// ─ Severity classification for order management ─
// CRITICAL = data integrity risk or customer-facing failure
// WARNING  = operational issue but recoverable
const CRITICAL_NODES = [
  'Log Order to Sheet',
  'Update Orders Master',
  'Append Status Log',
  'Log Problem Order',
  'Update Inventory Sheet',
  'WooCommerce — Keep Processing',
  'WooCommerce — Hold or Cancel',
  'Email Customer — Status Update'
];
const CRITICAL_WORKFLOWS = [
  'Order Flow 1',
  'Order Flow 3'
];

const isCritical = CRITICAL_NODES.includes(nodeName) ||
  CRITICAL_WORKFLOWS.some(w => workflowName.includes(w));

const severity = isCritical ? 'CRITICAL' : 'WARNING';
const severityEmoji = isCritical ? ':red_circle:' : ':warning:';

const criticalNote = isCritical
  ? '\n*Note:* This may have left an order in an inconsistent state. Check the Orders Master sheet and WooCommerce admin manually.'
  : '';

const subject = `${isCritical ? '[CRITICAL]' : '[WARNING]'} n8n Order Error — ${workflowName} — ${nodeName}`;

const html = `
<h2 style='color:${isCritical ? '#c0392b' : '#e67e22'}'>
  ${isCritical ? 'CRITICAL' : 'WARNING'} — Order Workflow Error
</h2>
<table border='1' cellpadding='8' style='border-collapse:collapse;width:100%'>
  <tr><td><b>Workflow</b></td><td>${workflowName}</td></tr>
  <tr><td><b>Failed Node</b></td><td>${nodeName}</td></tr>
  <tr><td><b>Error</b></td><td style='color:#c0392b'>${errorMsg}</td></tr>
  <tr><td><b>Severity</b></td><td>${severity}</td></tr>
  <tr><td><b>Execution ID</b></td><td>${execId}</td></tr>
  <tr><td><b>Time</b></td><td>${timestamp}</td></tr>
  ${execUrl ? `<tr><td><b>View Execution</b></td><td><a href='${execUrl}'>${execUrl}</a></td></tr>` : ''}
</table>
${isCritical ? '<p style="color:#c0392b"><b>This may have left an order in an inconsistent state. Manually check Orders Master sheet and WooCommerce admin.</b></p>' : ''}
${errorStack ? `<details><summary style='margin-top:12px;cursor:pointer'>Stack trace</summary><pre style='background:#f5f5f5;padding:12px;font-size:12px'>${errorStack}</pre></details>` : ''}
`;

const slackText = [
  `${severityEmoji} *[${severity}] Order Workflow Error*`,
  `*Workflow:* ${workflowName}`,
  `*Node:* ${nodeName}`,
  `*Error:* ${errorMsg}`,
  `*Time:* ${timestamp}`,
  execUrl ? `*Execution:* ${execUrl}` : '',
  criticalNote
].filter(Boolean).join('\n');

return [{
  json: {
    subject, html, slack_text: slackText,
    severity, workflow_name: workflowName,
    node_name: nodeName, error_message: errorMsg,
    exec_id: execId, timestamp, is_critical: isCritical
  }
}];
